from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character into a single fluent sentence.
    """
    if not triples:
        return ""

    # Use the subject of the first triple as the main subject of the sentence
    main_subject = triples[0].subject
    clauses = []

    for triple in triples:
        p = triple.predicate
        o = triple.object

        # Map predicates to natural‑language fragments
        if p == "alternativeName":
            clauses.append(f"also known as {o}")
        elif p == "creator":
            clauses.append(f"created by {o}")
        elif p == "fullName":
            clauses.append(f"full name {o}")
        elif p == "foundedBy":
            clauses.append(f"founded by {o}")
        elif p == "keyPerson":
            clauses.append(f"key person {o}")
        elif p == "city":
            clauses.append(f"based in {o}")
        elif p == "product":
            clauses.append(f"produces {o}")
        elif p == "lastAired":
            clauses.append(f"last aired on {o}")
        elif p == "starring":
            clauses.append(f"starring {o}")
        elif p == "firstAppearanceInFilm":
            clauses.append(f"first appeared in the film {o}")
        elif p == "voice":
            clauses.append(f"voiced by {o}")
        elif p == "distributor":
            clauses.append(f"distributed by {o}")
        elif p == "birthPlace":
            clauses.append(f"born in {o}")
        elif p == "nationality":
            clauses.append(f"is {o}")
        elif p == "award":
            clauses.append(f"won the {o}")
        elif p == "broadcastedBy":
            clauses.append(f"broadcasted by {o}")
        elif p == "firstAired":
            clauses.append(f"first aired on {o}")
        elif p == "series":
            clauses.append(f"part of the series {o}")
        elif p == "child":
            clauses.append(f"has child {o}")
        else:
            # Fallback for any unexpected predicate
            clauses.append(f"{p} {o}")

    # Join the clauses into a coherent sentence
    if clauses:
        sentence = f"{main_subject} " + ", ".join(clauses) + "."
    else:
        sentence = f"{main_subject}."

    # Capitalize the first character for proper formatting
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

